slides.codeSnippet:
// The ugly way (Lambda is inside the parentheses)
runTwice({ println("Ugly!") })

// The Trailing Lambda way! (Lambda sits outside)
runTwice() {
    println("So much cleaner!")
}

// We started here:
runTwice( { println("Ugly") } )

// Then we moved the Lambda outside:
runTwice() { println("Better") }

// Finally, we delete the empty ():
runTwice { 
    println("Perfection.") 
}
